18→
19→    @Resource
20→    private ISpaceNodeStarService spaceNodeStarService;
21→
22→    @Resource
23→    private ISpaceNodeService spaceNodeService;
24→
25→    @Resource
26→    private SpaceNodeTransfer spaceNodeTransfer;
27→
28→    @Override
29→    @Transactional
30→    public SpaceNodeVo starSpaceNode(Long spaceNodeId, Long userId) {
31→        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(spaceNodeId);
32→        ExceptionUtil.isNotNull(spaceNodeEntity, SpaceNodeException.NOT_EXIST);
33→
34→        SpaceNodeStarEntity existStar = spaceNodeStarService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
35→        if (existStar == null) {
36→            SpaceNodeStarEntity newStar = SpaceNodeStarEntity.builder()
37→                    .spaceNodeId(spaceNodeId)
38→                    .userId(userId)
39→                    .build();
40→            spaceNodeStarService.save(newStar);
41→        }
42→
43→        return spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
44→    }
45→
46→    @Override
47→    @Transactional
48→    public SpaceNodeVo unstarSpaceNode(Long spaceNodeId, Long userId) {
49→        SpaceNodeEntity spaceNodeEntity = spaceNodeService.getById(spaceNodeId);
50→        ExceptionUtil.isNotNull(spaceNodeEntity, SpaceNodeException.NOT_EXIST);
51→
52→        SpaceNodeStarEntity existStar = spaceNodeStarService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
53→        if (existStar != null) {
54→            spaceNodeStarService.removeById(existStar);
55→        }
56→
57→        return spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
58→    }
59→}
