22→@Service
23→public class SpaceNodeStarQueryManagerImpl implements SpaceNodeStarQueryManager {
24→
25→    @Resource
26→    private ISpaceNodeStarService spaceNodeStarService;
27→
28→    @Resource
29→    private ISpaceNodeService spaceNodeService;
30→
31→    @Resource
32→    private SpaceNodeTransfer spaceNodeTransfer;
33→
34→    @Override
35→    public IPage<SpaceNodeVo> queryStarredSpaceNodes(Long userId, StarQueryRo ro) {
36→        IPage<SpaceNodeStarEntity> starPage = spaceNodeStarService.getStarredPageByUserId(userId, ro.getPageNum(), ro.getPageSize());
37→
38→        List<SpaceNodeStarEntity> starList = starPage.getRecords();
39→        if (CollectionUtils.isEmpty(starList)) return new Page<>(ro.getPageNum(), ro.getPageSize(), 0);
40→
41→        List<Long> starredNodeIds = starList.stream().map(SpaceNodeStarEntity::getSpaceNodeId).toList();
42→        List<SpaceNodeEntity> spaceNodeEntities = spaceNodeService.listByIds(starredNodeIds);
43→
44→        Map<Long, SpaceNodeEntity> spaceNodeMap = spaceNodeEntities.stream()
45→                .collect(Collectors.toMap(SpaceNodeEntity::getId, spaceNode -> spaceNode));
46→        // sort by starList
47→        List<SpaceNodeEntity> sortedSpaceNodeEntities = starList.stream()
48→                .map(star -> spaceNodeMap.get(star.getSpaceNodeId()))
49→                .filter(Objects::nonNull)
50→                .toList();
51→
52→        List<SpaceNodeVo> vos = spaceNodeTransfer.toSpaceNodeVoWithRole(sortedSpaceNodeEntities);
53→
54→        return new Page<SpaceNodeVo>(starPage.getCurrent(), starPage.getSize(), starPage.getTotal()).setRecords(vos);
55→    }
56→}
