        ExceptionUtil.isNotNull(spaceNodeEntity, SpaceNodeException.NOT_EXIST);

        SpaceNodeStarEntity existStar = spaceNodeStarService.getByUserIdAndSpaceNodeId(userId, spaceNodeId);
        if (existStar != null) {
            spaceNodeStarService.removeById(existStar);
        }

        return spaceNodeTransfer.toSpaceNodeVo(spaceNodeEntity);
